import { useState, useEffect } from 'react';
import { BrowserRouter, Routes, Route, Navigate } from 'react-router-dom';
import { LogOut, LayoutDashboard } from 'lucide-react';
import { Toaster, toast } from 'react-hot-toast';
import { socket } from './socket';
import Auth from './components/Auth';
import AdminLogin from './components/AdminLogin';
import RestaurantDashboard from './components/RestaurantDashboard';
import NGODashboard from './components/NGODashboard';
import AdminDashboard from './components/AdminDashboard';
import api from './api';

export default function App() {
  const [user, setUser] = useState(null);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    // Check if logged in already on refresh
    const checkAuth = async () => {
      const token = localStorage.getItem('token');
      if (token) {
        try {
          const res = await api.get('/auth/user');
          setUser(res.data);
        } catch (err) {
          localStorage.removeItem('token');
        }
      }
      setLoading(false);
    };
    checkAuth();
  }, []);

  useEffect(() => {
    const handleNewPost = (post) => toast.success(`New Food Available: ${post.foodName}!`);
    const handleNewRequest = () => toast('New food request received!', { icon: '≡ƒæÅ' });
    const handleRequestUpdate = (req) => toast(`Request status changed to ${req.requestStatus}`);

    socket.on('newFoodPost', handleNewPost);
    socket.on('newFoodRequest', handleNewRequest);
    socket.on('requestStatusUpdated', handleRequestUpdate);

    return () => {
      socket.off('newFoodPost', handleNewPost);
      socket.off('newFoodRequest', handleNewRequest);
      socket.off('requestStatusUpdated', handleRequestUpdate);
    };
  }, []);

  const handleLogin = (data) => {
    localStorage.setItem('token', data.token);
    setUser(data.user);
  };

  const handleLogout = () => {
    localStorage.removeItem('token');
    setUser(null);
  };

  if (loading) return <div style={{ minHeight: '100vh', display: 'flex', alignItems: 'center', justifyContent: 'center' }}>Loading System...</div>;

  return (
    <BrowserRouter>
      <Toaster position="top-right" toastOptions={{ style: { background: 'var(--bg-card)', color: 'var(--text-main)', border: '1px solid var(--border)' } }} />
      <div className="container">
        {/* Universal Navigation */}
        <nav className="nav-bar">
          <div className="logo">
            <LayoutDashboard size={28} />
            FoodSurplus<span style={{ fontWeight: 300 }}>Network</span>
          </div>

          {user && (
            <div style={{ display: 'flex', alignItems: 'center', gap: '16px' }}>
              <span style={{ fontSize: '0.9rem', color: 'var(--text-muted)' }}>
                Logged in as <strong>{user.username || 'User'}</strong>
              </span>
              <button className="btn btn-outline" onClick={handleLogout} style={{ padding: '8px 16px', fontSize: '0.9rem' }}>
                <LogOut size={16} /> Logout
              </button>
            </div>
          )}
        </nav>

        {/* Dynamic Route Switching Based on Role */}
        <div style={{ paddingBottom: '60px' }}>
          {!user ? (
            <Routes>
              <Route path="/admin-login" element={<AdminLogin onLogin={handleLogin} />} />
              <Route path="*" element={<Auth onLogin={handleLogin} />} />
            </Routes>
          ) : user.role === 'RESTAURANT' ? (
            <RestaurantDashboard />
          ) : user.role === 'NGO' ? (
            <NGODashboard />
          ) : user.role === 'ADMIN' ? (
            <AdminDashboard />
          ) : (
            <div className="glass-card" style={{ textAlign: 'center', color: '#ef4444' }}>
              Unknown Role Detected
            </div>
          )}
        </div>
      </div>
    </BrowserRouter>
  );
}

import { useState, useEffect } from 'react';
import { ShieldCheck, UserX, UserCheck, TrendingUp } from 'lucide-react';
import { BarChart, Bar, XAxis, YAxis, CartesianGrid, Tooltip as RechartsTooltip, Legend, ResponsiveContainer, PieChart, Pie, Cell } from 'recharts';
import api from '../api';
import ChangePassword from './ChangePassword';

export default function AdminDashboard() {
  const [restaurants, setRestaurants] = useState([]);
  const [ngos, setNgos] = useState([]);
  const [allRestaurants, setAllRestaurants] = useState([]);
  const [allNgos, setAllNgos] = useState([]);
  const [messages, setMessages] = useState({});
  const [loading, setLoading] = useState(true);
  const [activeTab, setActiveTab] = useState('pending'); // 'pending' or 'all'
  const [statusFilter, setStatusFilter] = useState('ALL'); // 'ALL', 'ACTIVE', 'INACTIVE'

  useEffect(() => {
    fetchPendingVerifications();
  }, []);

  const fetchPendingVerifications = async () => {
    try {
      const res = await api.get('/admin/verifications');
      setRestaurants(res.data.restaurants);
      setNgos(res.data.ngos);

      const allRes = await api.get('/admin/entities');
      setAllRestaurants(allRes.data.restaurants);
      setAllNgos(allRes.data.ngos);

      setLoading(false);
    } catch (err) {
      alert('Failed to load admin data');
      setLoading(false);
    }
  };

  const handleVerify = async (type, id, status) => {
    try {
      const message = messages[`${type}-${id}`] || '';
      if ((status === 'REVERTED' || status === 'REJECTED') && !message) {
          return alert('Please provide an Admin Feedback message to Revert or Reject.');
      }
      await api.put(`/admin/verify/${type}/${id}`, { status, message });

      let successMsg = '';
      if (status === 'APPROVED') successMsg = 'Γ£à Application successfully approved. The user has been notified.';
      else if (status === 'REVERTED') successMsg = 'ΓÜá∩╕Å Application successfully reverted. The user has been asked to provide the requested info via email.';
      else if (status === 'REJECTED') successMsg = 'Γ¥î Application has been cleanly rejected.';
      alert(successMsg);

      fetchPendingVerifications();
      setMessages(prev => ({ ...prev, [`${type}-${id}`]: '' }));
    } catch (err) {
      alert(err.response?.data?.msg || 'Error updating verification');
    }
  };

  if (loading) return <div>Loading Admin Panel...</div>;

  const COLORS = ['#10b981', '#f59e0b', '#ef4444'];
  const pieData = [
    { name: 'Pending Restaurants', value: restaurants.length },
    { name: 'Pending NGOs', value: ngos.length }
  ];

  const barData = [
    { name: 'Restaurants', Active: allRestaurants.filter(r => r.verificationStatus === 'APPROVED').length, Pending: allRestaurants.filter(r => r.verificationStatus === 'PENDING' || r.verificationStatus === 'REVERTED').length },
    { name: 'NGOs', Active: allNgos.filter(n => n.verificationStatus === 'APPROVED').length, Pending: allNgos.filter(n => n.verificationStatus === 'PENDING' || n.verificationStatus === 'REVERTED').length }
  ];

  return (
    <div className="animate-fade-in">
      <div style={{ background: 'linear-gradient(135deg, rgba(245, 158, 11, 0.1), rgba(239, 68, 68, 0.1))', padding: '24px', borderRadius: '16px', border: '1px solid rgba(245, 158, 11, 0.2)', marginBottom: '32px' }}>
        <h2 style={{ display: 'flex', alignItems: 'center', gap: '12px', color: '#f59e0b' }}>
          <ShieldCheck size={28} /> Admin Control Panel
        </h2>
        <p style={{ marginTop: '8px', color: 'lightgray' }}>Review and securely authorize new network entities before they can post or claim surplus food.</p>
      </div>

      <div style={{ display: 'flex', gap: '16px', marginBottom: '24px' }}>
        <button 
          className="btn" 
          onClick={() => setActiveTab('pending')}
          style={{ 
            background: activeTab === 'pending' ? 'linear-gradient(135deg, var(--primary), var(--primary-hover))' : 'rgba(255,255,255,0.05)',
            border: `1px solid ${activeTab === 'pending' ? 'var(--primary)' : 'var(--border)'}`,
            color: 'white'
          }}
        >
          Pending Verifications
        </button>
        <button 
          className="btn" 
          onClick={() => setActiveTab('all')}
          style={{ 
            background: activeTab === 'all' ? 'linear-gradient(135deg, var(--accent), #2563eb)' : 'rgba(255,255,255,0.05)',
            border: `1px solid ${activeTab === 'all' ? 'var(--accent)' : 'var(--border)'}`,
            color: 'white'
          }}
        >
          Entity Database
        </button>
        <button 
          className="btn" 
          onClick={() => setActiveTab('stats')}
          style={{ 
            background: activeTab === 'stats' ? 'linear-gradient(135deg, #8b5cf6, #7c3aed)' : 'rgba(255,255,255,0.05)',
            border: `1px solid ${activeTab === 'stats' ? '#8b5cf6' : 'var(--border)'}`,
            color: 'white'
          }}
        >
          Analytics & Reports
        </button>
      </div>

      {activeTab === 'pending' ? (
        <div className="dashboard-grid animate-fade-in">
        {/* Pending Restaurants */}
        <div className="glass-card">
          <h3 style={{ marginBottom: '16px', color: 'var(--primary)' }}>Pending Restaurants</h3>
          {restaurants.length === 0 ? (
            <p>No restaurants pending verification.</p>
          ) : (
            <div style={{ display: 'flex', flexDirection: 'column', gap: '12px' }}>
              {restaurants.map(rest => (
                <div key={rest.restaurantId} style={{ background: 'rgba(0, 0, 0, 0.2)', padding: '16px', borderRadius: '8px', border: '1px solid var(--border)' }}>
                  <h4 style={{ marginBottom: '4px' }}>{rest.restaurantName}</h4>
                  <p style={{ fontSize: '0.85rem', marginBottom: '2px' }}>Registered by user: {rest.User?.username}</p>
                  <p style={{ fontSize: '0.85rem', marginBottom: '2px' }}><strong>Address:</strong> {rest.address}</p>
                  <p style={{ fontSize: '0.85rem', marginBottom: '4px' }}><strong>Govt Cert ID:</strong> {rest.registrationCertificate}</p>
                  {rest.documentUrl && (
                    <a href={`http://localhost:5000${rest.documentUrl}`} target="_blank" rel="noreferrer" style={{ fontSize: '0.85rem', color: 'var(--primary)', marginBottom: '12px', display: 'inline-block' }}>≡ƒôä View Uploaded Document</a>
                  )}

                  <div style={{ marginBottom: '12px' }}>
                    <textarea 
                      placeholder="Optional Admin Feedback (Required for Revert/Reject)..." 
                      value={messages[`restaurant-${rest.restaurantId}`] || ''}
                      onChange={(e) => setMessages({...messages, [`restaurant-${rest.restaurantId}`]: e.target.value })}
                      style={{ width: '100%', padding: '8px', borderRadius: '4px', background: 'rgba(255,255,255,0.05)', border: '1px solid var(--border)', color: 'white', fontSize: '0.85rem' }}
                      rows={2}
                    />
                  </div>

                  <div style={{ display: 'flex', gap: '8px' }}>
                    <button 
                      onClick={() => handleVerify('restaurant', rest.restaurantId, 'APPROVED')}
                      className="btn" style={{ flex: 1, padding: '8px', fontSize: '0.8rem', background: 'rgba(16, 185, 129, 0.2)', color: '#34d399', border: '1px solid #10b981' }}
                    >
                      <UserCheck size={14} /> Approve
                    </button>
                    <button 
                      onClick={() => handleVerify('restaurant', rest.restaurantId, 'REVERTED')}
                      className="btn" style={{ flex: 1, padding: '8px', fontSize: '0.8rem', background: 'rgba(245, 158, 11, 0.2)', color: '#f59e0b', border: '1px solid #f59e0b' }}
                    >
                      Revert
                    </button>
                    <button 
                      onClick={() => handleVerify('restaurant', rest.restaurantId, 'REJECTED')}
                      className="btn" style={{ flex: 1, padding: '8px', fontSize: '0.8rem', background: 'rgba(239, 68, 68, 0.2)', color: '#f87171', border: '1px solid #ef4444' }}
                    >
                      <UserX size={14} /> Reject
                    </button>
                  </div>
                </div>
              ))}
            </div>
          )}
        </div>

        {/* Pending NGOs */}
        <div className="glass-card">
          <h3 style={{ marginBottom: '16px', color: 'var(--accent)' }}>Pending NGOs</h3>
          {ngos.length === 0 ? (
            <p>No NGOs pending verification.</p>
          ) : (
            <div style={{ display: 'flex', flexDirection: 'column', gap: '12px' }}>
              {ngos.map(ngo => (
                <div key={ngo.ngoId} style={{ background: 'rgba(0, 0, 0, 0.2)', padding: '16px', borderRadius: '8px', border: '1px solid var(--border)' }}>
                  <h4 style={{ marginBottom: '4px' }}>{ngo.ngoName}</h4>
                  <p style={{ fontSize: '0.85rem', marginBottom: '2px' }}>Registered by user: {ngo.User?.username}</p>
                  <p style={{ fontSize: '0.85rem', marginBottom: '2px' }}><strong>Address:</strong> {ngo.address}</p>
                  <p style={{ fontSize: '0.85rem', marginBottom: '4px' }}><strong>Govt Cert ID:</strong> {ngo.registrationCertificate}</p>
                  {ngo.documentUrl && (
                    <a href={`http://localhost:5000${ngo.documentUrl}`} target="_blank" rel="noreferrer" style={{ fontSize: '0.85rem', color: 'var(--primary)', marginBottom: '12px', display: 'inline-block' }}>≡ƒôä View Uploaded Document</a>
                  )}

                  <div style={{ marginBottom: '12px' }}>
                    <textarea 
                      placeholder="Optional Admin Feedback (Required for Revert/Reject)..." 
                      value={messages[`ngo-${ngo.ngoId}`] || ''}
                      onChange={(e) => setMessages({...messages, [`ngo-${ngo.ngoId}`]: e.target.value })}
                      style={{ width: '100%', padding: '8px', borderRadius: '4px', background: 'rgba(255,255,255,0.05)', border: '1px solid var(--border)', color: 'white', fontSize: '0.85rem' }}
                      rows={2}
                    />
                  </div>

                  <div style={{ display: 'flex', gap: '8px' }}>
                    <button 
                      onClick={() => handleVerify('ngo', ngo.ngoId, 'APPROVED')}
                      className="btn" style={{ flex: 1, padding: '8px', fontSize: '0.8rem', background: 'rgba(16, 185, 129, 0.2)', color: '#34d399', border: '1px solid #10b981' }}
                    >
                      <UserCheck size={14} /> Approve
                    </button>
                    <button 
                      onClick={() => handleVerify('ngo', ngo.ngoId, 'REVERTED')}
                      className="btn" style={{ flex: 1, padding: '8px', fontSize: '0.8rem', background: 'rgba(245, 158, 11, 0.2)', color: '#f59e0b', border: '1px solid #f59e0b' }}
                    >
                      Revert
                    </button>
                    <button 
                      onClick={() => handleVerify('ngo', ngo.ngoId, 'REJECTED')}
                      className="btn" style={{ flex: 1, padding: '8px', fontSize: '0.8rem', background: 'rgba(239, 68, 68, 0.2)', color: '#f87171', border: '1px solid #ef4444' }}
                    >
                      <UserX size={14} /> Reject
                    </button>
                  </div>
                </div>
              ))}
            </div>
          )}
        </div>
        </div>
      ) : (
        <div className="glass-card animate-fade-in">
          <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: '24px' }}>
            <h3 style={{ color: 'var(--accent)' }}>System Entity Database</h3>
            <div style={{ display: 'flex', alignItems: 'center', gap: '8px' }}>
              <span style={{ fontSize: '0.9rem', color: 'var(--text-muted)' }}>Filter Entities:</span>
              <select 
                value={statusFilter} 
                onChange={(e) => setStatusFilter(e.target.value)}
                style={{ background: 'rgba(0,0,0,0.3)', color: 'white', border: '1px solid var(--border)', padding: '6px 12px', borderRadius: '8px', outline: 'none' }}
              >
                <option value="ALL">All Statuses</option>
                <option value="ACTIVE">Active (Approved)</option>
                <option value="INACTIVE">Inactive (Pending/Reverted/Rejected)</option>
              </select>
            </div>
          </div>

          <div className="dashboard-grid">
            {/* All Restaurants */}
            <div>
              <h4 style={{ marginBottom: '12px', color: 'var(--text-muted)' }}>Restaurants Directory</h4>
              <div style={{ display: 'flex', flexDirection: 'column', gap: '12px' }}>
                {allRestaurants
                  .filter(rest => {
                    if (statusFilter === 'ALL') return true;
                    const isActive = rest.verificationStatus === 'APPROVED';
                    return statusFilter === 'ACTIVE' ? isActive : !isActive;
                  })
                  .map(rest => (
                  <div key={rest.restaurantId} className="list-item" style={{ background: 'rgba(0, 0, 0, 0.2)', borderRadius: '8px', padding: '12px 16px', display: 'flex', flexDirection: 'column', alignItems: 'flex-start', gap: '8px' }}>
                    <div style={{ width: '100%', display: 'flex', justifyContent: 'space-between', alignItems: 'flex-start' }}>
                      <div>
                        <h4 style={{ marginBottom: '4px' }}>{rest.restaurantName}</h4>
                        <p style={{ fontSize: '0.85rem' }}>{rest.User?.email}</p>
                      </div>
                      <span className={`badge ${rest.verificationStatus === 'APPROVED' ? 'badge-success' : 'badge-warning'}`} style={{ fontSize: '0.7rem' }}>
                        {rest.verificationStatus}
                      </span>
                    </div>
                  </div>
                ))}
                {allRestaurants.filter(rest => {
                    const isActive = rest.verificationStatus === 'APPROVED';
                    return statusFilter === 'ALL' || (statusFilter === 'ACTIVE' ? isActive : !isActive);
                }).length === 0 && <p style={{ fontSize: '0.9rem', color: 'var(--text-muted)' }}>No restaurants found matching filter.</p>}
              </div>
            </div>

            {/* All NGOs */}
            <div>
              <h4 style={{ marginBottom: '12px', color: 'var(--text-muted)' }}>NGOs Directory</h4>
              <div style={{ display: 'flex', flexDirection: 'column', gap: '12px' }}>
                {allNgos
                  .filter(ngo => {
                    if (statusFilter === 'ALL') return true;
                    const isActive = ngo.verificationStatus === 'APPROVED';
                    return statusFilter === 'ACTIVE' ? isActive : !isActive;
                  })
                  .map(ngo => (
                  <div key={ngo.ngoId} className="list-item" style={{ background: 'rgba(0, 0, 0, 0.2)', borderRadius: '8px', padding: '12px 16px', display: 'flex', flexDirection: 'column', alignItems: 'flex-start', gap: '8px' }}>
                    <div style={{ width: '100%', display: 'flex', justifyContent: 'space-between', alignItems: 'flex-start' }}>
                      <div>
                        <h4 style={{ marginBottom: '4px' }}>{ngo.ngoName}</h4>
                        <p style={{ fontSize: '0.85rem' }}>{ngo.User?.email}</p>
                      </div>
                      <span className={`badge ${ngo.verificationStatus === 'APPROVED' ? 'badge-success' : 'badge-warning'}`} style={{ fontSize: '0.7rem' }}>
                        {ngo.verificationStatus}
                      </span>
                    </div>
                  </div>
                ))}
                {allNgos.filter(ngo => {
                    const isActive = ngo.verificationStatus === 'APPROVED';
                    return statusFilter === 'ALL' || (statusFilter === 'ACTIVE' ? isActive : !isActive);
                }).length === 0 && <p style={{ fontSize: '0.9rem', color: 'var(--text-muted)' }}>No NGOs found matching filter.</p>}
              </div>
            </div>
          </div>

        </div>
      ) : activeTab === 'stats' ? (
        <div className="glass-card animate-fade-in" style={{ padding: '32px' }}>
          <h3 style={{ marginBottom: '24px', color: '#8b5cf6', display: 'flex', alignItems: 'center', gap: '8px' }}>
            <TrendingUp size={24} /> Network Statistics
          </h3>

          <div className="dashboard-grid">
            <div style={{ background: 'rgba(0,0,0,0.2)', padding: '24px', borderRadius: '16px', border: '1px solid var(--border)' }}>
              <h4 style={{ marginBottom: '16px', textAlign: 'center' }}>Registration Status</h4>
              <div style={{ height: '300px' }}>
                <ResponsiveContainer width="100%" height="100%">
                  <BarChart data={barData} margin={{ top: 20, right: 30, left: 0, bottom: 5 }}>
                    <CartesianGrid strokeDasharray="3 3" stroke="rgba(255,255,255,0.1)" />
                    <XAxis dataKey="name" stroke="var(--text-muted)" />
                    <YAxis stroke="var(--text-muted)" allowDecimals={false} />
                    <RechartsTooltip cursor={{fill: 'rgba(255,255,255,0.05)'}} contentStyle={{ backgroundColor: 'var(--bg-dark)', borderColor: 'var(--border)', borderRadius: '8px' }} />
                    <Legend />
                    <Bar dataKey="Active" fill="#10b981" radius={[4, 4, 0, 0]} />
                    <Bar dataKey="Pending" fill="#f59e0b" radius={[4, 4, 0, 0]} />
                  </BarChart>
                </ResponsiveContainer>
              </div>
            </div>

            <div style={{ background: 'rgba(0,0,0,0.2)', padding: '24px', borderRadius: '16px', border: '1px solid var(--border)' }}>
              <h4 style={{ marginBottom: '16px', textAlign: 'center' }}>Pending Workload</h4>
              <div style={{ height: '300px' }}>
                <ResponsiveContainer width="100%" height="100%">
                  <PieChart>
                    <Pie
                      data={pieData}
                      cx="50%"
                      cy="50%"
                      innerRadius={60}
                      outerRadius={100}
                      paddingAngle={5}
                      dataKey="value"
                      label={({name, percent}) => `${name} ${(percent * 100).toFixed(0)}%`}
                    >
                      {pieData.map((entry, index) => (
                        <Cell key={`cell-${index}`} fill={COLORS[index % COLORS.length]} />
                      ))}
                    </Pie>
                    <RechartsTooltip contentStyle={{ backgroundColor: 'var(--bg-dark)', borderColor: 'var(--border)', borderRadius: '8px' }} />
                  </PieChart>
                </ResponsiveContainer>
              </div>
            </div>
          </div>
        </div>
      ) : null}

      <ChangePassword />
    </div>
  );
}

import { useState } from 'react';
import { Store, HeartHandshake, LogIn } from 'lucide-react';
import api from '../api';

export default function Auth({ onLogin }) {
  const [isLogin, setIsLogin] = useState(true); // Default to Login mode
  const [step, setStep] = useState(1); // Multistep for registration
  const [role, setRole] = useState('RESTAURANT'); // RESTAURANT or NGO
  const [form, setForm] = useState({ username: '', password: '', email: '', contactNumber: '', address: '', registrationCertificate: '' });
  const [documentFile, setDocumentFile] = useState(null);
  const [error, setError] = useState('');
  const [successMsg, setSuccessMsg] = useState('');

  const handleSubmit = async (e) => {
    e.preventDefault();
    setError('');

    if (!isLogin && step < 3) {
      setStep(step + 1);
      return;
    }

    try {
      if (isLogin) {
        const { data } = await api.post('/auth/login', form);
        if (data.user?.role === 'ADMIN') {
            throw { response: { data: { msg: 'Administrators must log in through the secure /admin secure portal.' } } };
        }
        onLogin(data);
      } else {
        const formData = new FormData();
        formData.append('username', form.username);
        formData.append('password', form.password);
        formData.append('email', form.email);
        formData.append('contactNumber', form.contactNumber);
        formData.append('role', role);
        formData.append('address', form.address);
        formData.append('registrationCertificate', form.registrationCertificate);
        if (documentFile) {
            formData.append('document', documentFile);
        }

        const { data } = await api.post('/auth/register', formData, {
            headers: { 'Content-Type': 'multipart/form-data' }
        });

        // Handle pending state
        setSuccessMsg('Registration successful! Please allow 24-48 hours for Admin verification before you can post/claim food.');
        setIsLogin(true); // Switch to login screen
        setStep(1); // Reset step
        setDocumentFile(null);
      }
    } catch (err) {
      setError(err.response?.data?.msg || err.response?.data?.errors?.[0]?.msg || 'Authentication failed');
    }
  };

  return (
    <div style={{ display: 'flex', justifyContent: 'center', alignItems: 'center', minHeight: '80vh' }}>
      <div className="glass-card animate-fade-in" style={{ width: '100%', maxWidth: '400px' }}>
        <h2 style={{ textAlign: 'center', marginBottom: '24px' }}>
          {isLogin ? 'Welcome Back!' : 'Join Food Surplus Network'}
        </h2>

